var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"제5 방위선 함락 후, 52시간 경과","JPN":"第5防衛線の陥落後、52時間経過","ENG":"52 hours after the fall of the 5th Defense Line","TWN":"第五防線淪陷後經過52小時","THA":"52 ชั่วโมงหลังจากการล่มสลายของแนวป้องกันที่ 5","VTN":"52 giờ sau khi Phòng Tuyến thứ 5 thất thủ","SCN":"第5防线沦陷，52小时后","DEU":"52 Stunden nach dem Fall der 5. Verteidigungslinie","FRA":"52 heures après la chute de la 5e ligne de défense"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제4 방위선, 거점 기지","JPN":"人類統合防衛軍第4防衛線、拠点基地","ENG":"Base, United Humankind Defense Force's 4th Defense Line","TWN":"人類共同保衛軍第四防線基地","THA":"กองทัพ แนวป้องกันที่ 4 กองกำลังป้องกันมนุษยชาติ ","VTN":"Căn cứ, Phòng Tuyến thứ 4 của Lực Lượng Phòng Vệ Nhân Loại Thống Nhất","SCN":"人类综合防卫军第4防线，据点基地","DEU":"Basis, 4. Verteidigungslinie der Verteidigungsstreitkräfte der vereinigten Menschheit","FRA":"Base de la 4e ligne de défense des Forces de défense unies de l'humanité"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"카운터 양성 계획?","JPN":"カウンター養成計画？","ENG":"Counter training project?","TWN":"制裁者培育計畫？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"그래, 따지고보면 소령은 내 선배쯤 된다고?","JPN":"ああ、つまり少佐はオレの先輩ってことになるな？","ENG":"Yeah. So technically, you, Major, are like my senior.","TWN":"嗯哼，算起來少校還是我的前輩吧？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그 프로젝트는, 분명 제 기수를 마지막으로 폐기되었을 텐데요?","JPN":"あのプロジェクトは、確か私の代を最後に廃止になったはずでは？","ENG":"I'm pretty sure that project got discontinued, with myself being one of the last candidates.","TWN":"那個計畫，明明最後已經廢止了吧？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"공식적으로는 그렇지.","JPN":"公式的にはな。","ENG":"Officially, yes.","TWN":"表面上是這樣。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"하지만 자네의 상관이었던 레지날드 준장은 음지에서 프로젝트를 이어나갔네.","JPN":"だが、君の上官であったレジナルド准将の手により、密かにプロジェクトは続けられた。","ENG":"But your superior, Brigadier General Dominic King Reginald, continued the project secretly.","TWN":"但你們的長官多明尼克準將暗地裡仍繼續進行這個計畫。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그는 원래부터 대의를 위해서라면 수단을 가리지 않는 성격이니 말이야.","JPN":"彼は元々、大義のためなら手段を選ばない性格だからな。","ENG":"He was always a stickler for doing anything for the greater good.","TWN":"他本來就是那種為達目的不擇手段的性格。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신, 우리 사령관님을 알고 있나요?","JPN":"あなた、私たちの司令官をご存じなんですか？","ENG":"You... You knew our commander?","TWN":"你……認識我們的司令官?"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그의 방식에 완전히 찬성하는 건 아니지만, 지금의 나라면 그를 이해할 수 있으니까.","JPN":"彼のやり方に完全に賛成するわけじゃないが、今の私なら彼を理解することができる。","ENG":"Although I don't completely agree with his methods, I can understand him now.","TWN":"我雖然不完全認可他的行事方式，但我現在可以理解他。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"흥! 이해고 나발이고 마음에 안 들어!","JPN":"ふん！　理解もなにも、オレは気に入らねえ！","ENG":"Hmph! Understanding or not, I don't like him!","TWN":"哼！什麼理解不理解的，我不喜歡他！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"그 인간은 나를 속이고, 실험용 쥐새끼처럼 대했단 말이야!","JPN":"あいつはオレを騙して、実験用のネズミみたいに扱ったんだ！","ENG":"He deceived me, and used me like some lab rat!","TWN":"那傢伙騙我，還把我當成實驗用的白老鼠！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"세계 멸망이니, 뭐니 헛소리나 잔뜩 떠들어대더니 먼저 뒈져버리고 말이야.","JPN":"世界の滅亡だの何だの、変なことばかり聞かせておいて、先に死んじまったしな。","ENG":"He always ranted nonsense about the world ending, and look where that got him. DEAD.","TWN":"什麼世界滅亡，滿嘴胡說八道，結果自己先死了。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"하지만 결국 레지날드 준장이 없었다면 자네는 지금 이 자리에 없었을 걸세.","JPN":"しかし結局のところ、レジナルド准将がいなければ、君は今この場にいなかっただろう。","ENG":"But if it were not for Brigadier General Dominic King Reginald, you would not be here right now.","TWN":"但要不是多明尼克準將，你現在也不會在這裡。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"과정은 어떻다 해도, 결과적으로 레지날드 준장은 자네를 구한 셈이 되네만?","JPN":"過程はともあれ、結果的にレジナルド准将は君を助けたことになるな？","ENG":"No matter the process, strictly looking at the results, he did save you, did he not?","TWN":"先不談過程，從結果來看，多明尼克準將也算救了你一命？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"그건…… 그래서 뭐, 어쩌란 거야. 그 자식한테 고마워라도 하라고?","JPN":"それは……だからって何だよ。あいつに感謝でもしろってのか？","ENG":"That's... So what? What do you want me to do? Thank him?","TWN":"那是……所以呢？那又怎樣？我還得跟那傢伙說聲謝謝嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};